patterns.form:
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Form } from '@vigee-designsystem/components/ui/form';
import Input from '@vigee-designsystem/components/Forms/Input';
import Select from '@vigee-designsystem/components/Forms/Select';
import Switch from '@vigee-designsystem/components/Forms/Switch';

const form = useForm({ resolver: zodResolver(schema), defaultValues: {...} });
<Form {...form}><form onSubmit={form.handleSubmit(onSubmit)}>
  <Input form={form} name="field" label="Label" />
</form></Form>

